class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLen = 0, zeros = 0, ones = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '0') zeros++;
            else ones++;
            if (zeros == ones) maxLen = Math.max(maxLen, zeros + ones);
            else if (ones > zeros) {
                zeros = ones = 0;
                zeros++;
            } else {
                ones = 0;
                ones++;
            }
        }
        return maxLen;
    }
}
